25	/** The field mapping contract the LLM must produce. */
26	export interface SchemaMapping {
27	    /** JSON path to the action/tool/function name */
28	    action_name: string;
29	    /** JSON path to the issue type / task category / intent */
30	    issue_type: string | null;
31	    /** JSON path to the success/failure indicator */
