70	// ── Configuration ─────────────────────────────────────────────
71	
72	const SAMPLE_SIZE = 5;
73	const MAX_SAMPLE_JSON_LENGTH = 8000; // chars per sample batch (avoid token bloat)
74	const LLM_TIMEOUT_MS = 10_000; // 10 second timeout on LLM calls
