76	// ── Schema Fingerprint Cache ──────────────────────────────────
77	// Caches mappings by schema fingerprint so the same data shape
78	// doesn't trigger redundant LLM calls across multiple uploads.
79	//
80	// Implemented as a true LRU: Map insertion order is preserved, and
81	// every cache hit moves the entry to the tail so least-recently-used
82	// entries are always at the head.
83	const mappingCache = new Map<string, SchemaMapping>();
84	const MAX_CACHE_SIZE = 100;
85	
86	// ── In-flight deduplication ───────────────────────────────────
87	// When N concurrent uploads share the same schema fingerprint and
88	// the mapping isn't cached yet, all N requests coalesce onto a
89	// single in-flight LLM promise instead of firing N separate calls.
90	// The promise is removed from the map the moment it settles (success
91	// or failure), so the next request after that goes through the
92	// normal LRU cache path.
93	const inflightCalls = new Map<
94	    string,
95	    Promise<{ result: InferResult | null; error: string | null }>
96	>();
97	
98	/** Clears the schema mapping cache and any in-flight calls. Exported for testing. */
99	export function clearMappingCache(): void {
100	    mappingCache.clear();
101	    inflightCalls.clear();
102	}
