104	/**
105	 * Builds a key-shape string for one record, recursing up to `maxDepth`
106	 * levels so that schemas differing only in nested field names produce
107	 * distinct fingerprints.
108	 */
109	function recordKeyShape(obj: Record<string, unknown>, depth: number): string {
110	    const keys = Object.keys(obj).sort();
111	    return keys.map((k) => {
112	        const v = obj[k];
113	        if (depth > 0 && typeof v === 'object' && v !== null && !Array.isArray(v)) {
114	            return `${k}:{${recordKeyShape(v as Record<string, unknown>, depth - 1)}}`;
115	        }
116	        return k;
117	    }).join('|');
118	}
119	
120	function computeSchemaFingerprint(records: Record<string, unknown>[]): string {
121	    // Use the key structure (3 levels deep) of the first 3 records.
122	    // Values don't matter — only the shape does.
123	    return records.slice(0, 3).map((r) => recordKeyShape(r, 2)).join('\n');
124	}
