217	// ── Mapping Validation ────────────────────────────────────────
218	
219	const REQUIRED_MAPPING_FIELDS: (keyof SchemaMapping)[] = ['action_name', 'success'];
220	const ALL_MAPPING_FIELDS: (keyof SchemaMapping)[] = [
221	    'action_name', 'issue_type', 'success', 'error_message', 'error_code',
222	    'response_time_ms', 'session_id', 'episode_id', 'environment',
223	    'outcome_score', 'business_outcome', 'timestamp', 'resource_cost_units',
224	    'retry_attempt', 'task_name', 'detected_framework', 'confidence',
225	];
