271	// ── Spot-Check: Validate the mapping against sample data ──────
272	
273	/**
274	 * After the LLM returns a mapping, we verify it actually extracts
275	 * valid data from the samples. If action_name or success can't be
276	 * resolved from the first 3 samples, we reject the mapping.
277	 *
278	 * This is the critical safety gate — the LLM can hallucinate paths
279	 * that don't exist. This function catches that.
280	 */
281	export function spotCheckMapping(
282	    mapping: SchemaMapping,
283	    samples: Record<string, unknown>[],
284	): { valid: boolean; error: string | null; extractionRate: number } {
285	    const checkSamples = samples.slice(0, Math.min(3, samples.length));
286	    let actionHits = 0;
287	    let successHits = 0;
288	
289	    for (const sample of checkSamples) {
290	        const actionVal = deepGet(sample, mapping.action_name);
291	        if (actionVal !== undefined && actionVal !== null && String(actionVal).trim().length > 0) {
292	            actionHits++;
293	        }
294	
295	        const successVal = deepGet(sample, mapping.success);
296	        if (successVal !== undefined && successVal !== null) {
297	            successHits++;
298	        }
299	    }
300	
301	    const actionRate = actionHits / checkSamples.length;
302	    const successRate = successHits / checkSamples.length;
303	
304	    if (actionRate < 0.67) {
305	        return {
306	            valid: false,
307	            error: `Mapping for "action_name" (path: "${mapping.action_name}") did not resolve in ${checkSamples.length - actionHits}/${checkSamples.length} samples.`,
308	            extractionRate: actionRate,
309	        };
310	    }
311	
312	    if (successRate < 0.67) {
313	        return {
314	            valid: false,
315	            error: `Mapping for "success" (path: "${mapping.success}") did not resolve in ${checkSamples.length - successHits}/${checkSamples.length} samples.`,
316	            extractionRate: successRate,
317	        };
318	    }
319	
320	    // Count how many optional fields resolved
321	    let optionalHits = 0;
322	    let optionalTotal = 0;
323	    const optionalPaths = [
324	        mapping.issue_type, mapping.error_message, mapping.response_time_ms,
325	        mapping.session_id, mapping.episode_id, mapping.timestamp,
326	    ].filter(Boolean) as string[];
327	
328	    for (const path of optionalPaths) {
329	        optionalTotal++;
330	        for (const sample of checkSamples) {
331	            const val = deepGet(sample, path);
332	            if (val !== undefined && val !== null) {
333	                optionalHits++;
334	                break; // found at least one hit for this path
335	            }
336	        }
337	    }
338	
339	    const overallRate = optionalTotal > 0
340	        ? (actionRate + successRate + (optionalHits / optionalTotal)) / 3
341	        : (actionRate + successRate) / 2;
342	
343	    return { valid: true, error: null, extractionRate: overallRate };
344	}
