346	// ── Apply Mapping to Records ──────────────────────────────────
347	
348	/**
349	 * Takes the LLM-inferred mapping and re-keys ALL records into
350	 * Layerinfinite's standard schema. This is the deterministic
351	 * hot-path — no LLM involved.
352	 */
353	export function applyMapping(
354	    records: Record<string, unknown>[],
355	    mapping: SchemaMapping,
356	): Record<string, unknown>[] {
357	    return records.map((record) => {
358	        const mapped: Record<string, unknown> = {};
359	
360	        // Required fields
361	        mapped.action_name = deepGet(record, mapping.action_name);
362	        mapped.success = deepGet(record, mapping.success);
363	
364	        // Optional fields — only set if path exists in mapping AND the value is
365	        // present in this record. Skipping undefined prevents downstream code
366	        // from seeing a key with an undefined value (e.g. 'session_id' in record
367	        // returning true with value undefined).
368	        const optionals: [string, string | null][] = [
369	            ['issue_type', mapping.issue_type],
370	            ['error_message', mapping.error_message],
371	            ['error_code', mapping.error_code],
372	            ['response_time_ms', mapping.response_time_ms],
373	            ['session_id', mapping.session_id],
374	            ['episode_id', mapping.episode_id],
375	            ['environment', mapping.environment],
376	            ['outcome_score', mapping.outcome_score],
377	            ['business_outcome', mapping.business_outcome],
378	            ['timestamp', mapping.timestamp],
379	            ['resource_cost_units', mapping.resource_cost_units],
380	            ['retry_attempt', mapping.retry_attempt],
381	            ['task_name', mapping.task_name],
382	        ];
383	        for (const [field, path] of optionals) {
384	            if (!path) continue;
385	            const val = deepGet(record, path);
386	            if (val !== undefined) mapped[field] = val;
387	        }
388	
389	        // Preserve the original record as raw_context for auditability
390	        mapped._original = record;
391	        mapped._inferred_by = 'schema-inferrer';
392	        mapped._detected_framework = mapping.detected_framework;
393	
394	        return mapped;
395	    });
396	}
